            Tags = """["reports","analytics","reference"]""",
            ContentJson = """{"title":"Reports Field Reference","groups":[{"heading":"What You Can Report On (28)","items":[{"label":"Jobs","value":"Production jobs — their stage, priority, customer, part, type, and dates."},{"label":"Parts","value":"Your parts list — part number, type, status, material, and vendor."},{"label":"Customers","value":"Customer records — name, company, email, phone, and whether they're active."},{"label":"Expenses","value":"Expenses — amount, category, status, date, the job they belong to, and approval."},{"label":"Time Entries","value":"Logged time — how long, what category, which job, and whether it was typed in by hand."},{"label":"Invoices","value":"Invoices — number, status, dates, payment terms, tax, customer, and order."},{"label":"Leads","value":"Sales leads — company, contact, where they came from, status, and follow-up date."},{"label":"Assets","value":"Equipment and tooling — type, status, run hours, and maker."},{"label":"Purchase Orders","value":"Purchase orders — number, status, dates, vendor, and related job."},{"label":"Sales Orders","value":"Sales orders — number, status, the customer's PO, payment terms, and customer."},{"label":"Quotes","value":"Quotes — number, status, dates, tax, and customer."},{"label":"Shipments","value":"Shipments — number, status, carrier, tracking, dates, cost, and weight."},{"label":"Inventory","value":"What's in each bin — item, quantity, amount reserved, lot number, and location."},{"label":"Payments","value":"Payments received — number, method, amount, date, and customer."},{"label":"Vendors","value":"Vendors — company, contact, address, payment terms, and whether they're active."},{"label":"Production Runs","value":"Production runs — run number, status, target and finished counts, scrap, and timing."},{"label":"Lot Records","value":"Lot tracking — lot number, quantity, expiration, supplier's lot, part, and job."},{"label":"QC Inspections","value":"Quality checks — result, lot number, job, run, checklist used, and inspector."},{"label":"Maintenance Schedules","value":"Planned upkeep — title, how often, last done, next due, and which asset."},{"label":"Maintenance Logs","value":"Upkeep history — when done, hours spent, cost, and which asset."},{"label":"Downtime Logs","value":"Equipment downtime — start and end, reason, fix, planned or not, and asset."},{"label":"Customer Returns","value":"Returns — number, status, reason, dates, inspection, and the original job."},{"label":"Bin Movements","value":"Inventory moves — item, quantity, lot, reason, and from and to location."},{"label":"Planning Cycles","value":"Planning cycles — name, status, dates, length, and goals."},{"label":"Invoice Lines","value":"Line items on invoices — description, quantity, unit price, and part."},{"label":"Sales Order Lines","value":"Line items on sales orders — description, quantity, unit price, amount shipped, and part."},{"label":"Purchase Order Lines","value":"Line items on purchase orders — description, amount ordered and received, unit price, and part."},{"label":"Quote Lines","value":"Line items on quotes — description, quantity, unit price, and part."}]},{"heading":"Kinds of Fields","items":[{"label":"Text","value":"Words, like a name or description. You can match all of it, part of it, or the start."},{"label":"Number","value":"Amounts, like price or quantity. You can match, compare, or set a range. Numbers can size a chart."},{"label":"Date","value":"Dates and times. You can match, compare, or set a range — and group by date to see trends."},{"label":"Yes / No","value":"True or false fields, like Active or Archived. You can filter on the answer or group by it."},{"label":"Choice","value":"A set list, like Status, Priority, or Type. You can filter by one or more, or group by them."}]},{"heading":"Ways to Filter","items":[{"label":"Is","value":"An exact match. Works on any field."},{"label":"Is not","value":"Anything except an exact match. Works on any field."},{"label":"Contains","value":"The text appears anywhere in the field. Not case-sensitive. For text fields."},{"label":"Starts with","value":"The text is at the beginning of the field. For text fields."},{"label":"More than","value":"Bigger than the value you enter. For numbers and dates."},{"label":"Less than","value":"Smaller than the value you enter. For numbers and dates."},{"label":"At least","value":"Equal to or bigger than the value you enter. For numbers and dates."},{"label":"At most","value":"Equal to or smaller than the value you enter. For numbers and dates."},{"label":"Between","value":"Falls within a range, including the two ends. Enter a low and a high value. For numbers and dates."},{"label":"Is empty","value":"The field was never filled in. No value to type."},{"label":"Is filled in","value":"The field has a value. No value to type."},{"label":"Is one of","value":"Matches any item in a list you type, separated by commas. For choice fields."}]},{"heading":"Chart Types","items":[{"label":"Bar","value":"Bars side by side. Best for comparing amounts, like jobs by stage or expenses by category. Needs a label and a number."},{"label":"Line","value":"A line with points. Best for trends over time, like completions or revenue. Needs a label and a number."},{"label":"Pie","value":"A circle split into slices. Best for showing shares of a whole, like leads by status. Needs a label and a number."},{"label":"Doughnut","value":"A pie with a hole in the middle. Good for status or type breakdowns. Needs a label and a number."},{"label":"Table","value":"Just the data, no chart. This is what you get if you don't pick a chart. Rows you can sort and filter."}]},{"heading":"Ways to Save or Share","items":[{"label":"CSV","value":"A spreadsheet file with every row and your chosen columns. Available after you run a report. Opens in Excel."},{"label":"PDF","value":"A tidy, formatted PDF with a heading and the data table, ready to send or file."},{"label":"Print","value":"Prints just the report and its chart — the menus and buttons drop away."}]},{"heading":"Saving a Report","items":[{"label":"Name (required)","value":"Up to 100 characters. This is how you'll find the report in the saved list later."},{"label":"Description","value":"Optional. A note about what the report shows."},{"label":"Share switch","value":"On means everyone who can see reports can use it. Off means only you can see it."},{"label":"Data","value":"The information you chose to report on (like Jobs or Parts). Saved for you."},{"label":"Columns","value":"The columns you picked. Saved for you."},{"label":"Filters","value":"Every filter you set up. Saved for you."},{"label":"Grouping","value":"How the results are grouped, if at all. Saved for you."},{"label":"Sorting","value":"The column you sort by and the direction. Saved for you."},{"label":"Chart","value":"The chart type and the fields behind it. Saved for you."}]},{"heading":"Buttons and Actions","items":[{"label":"Report names","value":"Click a ready-made report to open it. The one you're viewing stays highlighted. 28 to choose from."},{"label":"Build Your Own","value":"Opens the page where you create your own custom report."},{"label":"Flow Diagrams","value":"Opens the flow diagrams page, with 10 diagrams that show how work moves along."},{"label":"Run Report","value":"Shows the results. Stays greyed out until you've picked what to report on and at least one column."},{"label":"Save","value":"Opens the save panel. Greyed out until the report can run. Asks for a name, a note, and the share switch."},{"label":"CSV","value":"Downloads the current results as a spreadsheet file. Appears once you've run a report."},{"label":"New Report","value":"Clears everything you've set up so you can start over."},{"label":"Open a saved report","value":"A menu of your saved reports. Pick one to load it, filters and all. The first choice is '-- None --'."},{"label":"Delete a saved report","value":"The red trash icon next to the saved-report menu. Shows only when a saved report is open. Deletes it."},{"label":"Add filter","value":"Adds another filter — a field, a comparison, and a value. Stack as many as you like."},{"label":"Remove filter","value":"The red X on a filter. Removes just that one."},{"label":"Click a chart","value":"Click a bar or slice to narrow the table to that piece. Click again to see everything."}]},{"heading":"Before It Can Run","items":[{"label":"Pick your data","value":"Required to run or save. Choose one of the 28 things you can report on."},{"label":"Pick columns","value":"You need at least one column before a report can run."},{"label":"Filter value","value":"Most filters need a value. 'Is empty' and 'Is filled in' don't."},{"label":"Chart fields","value":"If you chose a chart other than a plain table, pick a label and a number for it."},{"label":"Save name","value":"Required, up to 100 characters."}]},{"heading":"Flow Diagrams (10)","items":[{"label":"Quote to Cash","value":"Follows work from quotes through orders, shipments, and invoices to payments. Needs a date range."},{"label":"Job Stage Flow","value":"Shows how jobs move from one stage to the next across job types."},{"label":"Material to Product","value":"Follows raw materials through production to finished parts."},{"label":"Worker Orders","value":"Shows work flowing from each worker to whether it's finished."},{"label":"Expense Flow","value":"Follows expense categories through approval to their final status. Needs a date range."},{"label":"Vendor Supply Chain","value":"Follows vendors through purchase orders to materials received."},{"label":"Quality Rejection","value":"Shows quality-check results splitting into pass, fail, and rework. Needs a date range."},{"label":"Inventory Location","value":"Shows how inventory is spread across storage areas and bins."},{"label":"Customer Revenue","value":"Follows customers through orders and invoices to revenue. Needs a date range."},{"label":"Training Completion","value":"Shows training moving from signed up to finished."}]}]}"""
