            Tags = """["reports","analytics","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"rpt1","text":"You want to see how many jobs are in each stage right now. Which ready-made report should you open?","options":[{"id":"a","text":"Jobs by Stage","isCorrect":true},{"id":"b","text":"Job Completion Trend"},{"id":"c","text":"Time in Stage"},{"id":"d","text":"Team Workload"}],"explanation":"Jobs by Stage shows a bar chart counting jobs in each stage. Job Completion Trend shows finishes over time, Time in Stage shows how long jobs sit in a stage, and Team Workload shows who's assigned what."},{"id":"rpt2","text":"When you build your own report, what's the least you have to set before you can run it?","options":[{"id":"a","text":"Pick what to report on and choose at least one column","isCorrect":true},{"id":"b","text":"Pick what to report on, add at least one filter, and choose a chart"},{"id":"c","text":"Pick what to report on — columns are chosen for you"},{"id":"d","text":"Open a saved report — you can't run a fresh one"}],"explanation":"Run Report lights up once you've picked what to report on and checked at least one column. Filters, grouping, sorting, and a chart are all optional."},{"id":"rpt3","text":"You need every invoice sent to one customer during the first quarter. How do you set this up when building your own report?","options":[{"id":"a","text":"Report on Invoices, filter Customer to that name, and filter Invoice Date to the quarter's start and end using Between","isCorrect":true},{"id":"b","text":"Report on Customers and filter by number of invoices"},{"id":"c","text":"Use the ready-made AR Aging report and filter by customer"},{"id":"d","text":"Report on Invoice Lines and group by customer name"}],"explanation":"Report on Invoices, then add two filters: one for the customer's name, and one for the invoice date set to Between the quarter's start and end. Between needs two dates — a low and a high."},{"id":"rpt4","text":"What does the 'Share' switch do when you save a report?","options":[{"id":"a","text":"On means everyone who can see reports can use it; off means only you can see it.","isCorrect":true},{"id":"b","text":"On saves the results so they load faster next time"},{"id":"c","text":"On sends a copy to a shared network drive"},{"id":"d","text":"On emails the report to all managers"}],"explanation":"The Share switch controls who can see the report. When it's on, anyone who can see reports (Admins, Managers, Office Managers, PMs) finds it in the saved list. When it's off, only you can see it."},{"id":"rpt5","text":"You want a pie chart of expenses by category. What do you set up?","options":[{"id":"a","text":"Choose a pie chart, use Category for the labels, and Amount for the size","isCorrect":true},{"id":"b","text":"Choose a pie chart and pick Category as the only column"},{"id":"c","text":"Choose a pie chart, group by Category, and sort by Amount"},{"id":"d","text":"Choose a bar chart with Category labels — pie charts aren't available"}],"explanation":"Any chart needs three things: the chart type (pie), what labels each slice (Category), and the number that sets each slice's size (Amount, which must be a number). Labels say what each slice is; the number says how big."},{"id":"rpt6","text":"Which filter finds every job that has no due date set?","options":[{"id":"a","text":"Is empty","isCorrect":true},{"id":"b","text":"Is, with a blank value"},{"id":"c","text":"Is not, with today's date"},{"id":"d","text":"Less than, with a very old date"}],"explanation":"'Is empty' finds records where the field was never filled in, and you don't type a value for it. That's the right way to find missing dates — not comparing against a blank or some old date."},{"id":"rpt7","text":"How many different things can you report on when building your own report?","options":[{"id":"a","text":"10"},{"id":"b","text":"20"},{"id":"c","text":"28","isCorrect":true},{"id":"d","text":"35"}],"explanation":"There are 28 to choose from, including Jobs, Parts, Customers, Expenses, Time Entries, Invoices, Leads, Assets, Purchase Orders, Sales Orders, Quotes, Shipments, Inventory, Payments, Vendors, Production Runs, Lot Records, QC Inspections, and more."},{"id":"rpt8","text":"You click a bar in a chart while building a report. What happens?","options":[{"id":"a","text":"The table below narrows to show only the rows behind that bar","isCorrect":true},{"id":"b","text":"A new report opens for that piece"},{"id":"c","text":"The bar lights up but nothing else changes"},{"id":"d","text":"The chart zooms into the bar to show smaller categories"}],"explanation":"Clicking a bar or slice narrows the table below to just the rows behind it. Click the same piece again to go back to the full list."},{"id":"rpt9","text":"Who can use the Reports page?","options":[{"id":"a","text":"Everyone, including Engineers and Production Workers"},{"id":"b","text":"Admins, Managers, Office Managers, and PMs only","isCorrect":true},{"id":"c","text":"Admins and Managers only"},{"id":"d","text":"Admins only"}],"explanation":"The full Reports page is for Admins, Managers, Office Managers, and PMs. Engineers and Production Workers don't have it, but they can still see their own reports (My Work History, My Time Log) from their own pages."},{"id":"rpt10","text":"You want a flow diagram showing how quotes turn into cash across the order's life. Where do you go?","options":[{"id":"a","text":"Reports → Flow Diagrams → Quote to Cash","isCorrect":true},{"id":"b","text":"Reports → ready-made → Quote-to-Close"},{"id":"c","text":"Reports → build your own → report on Quotes"},{"id":"d","text":"Dashboard → money widget"}],"explanation":"Quote to Cash is one of 10 flow diagrams under Reports → Flow Diagrams. It follows work from quotes through orders, shipments, and invoices to payments. The ready-made Quote-to-Close report shows conversion rates, not the flow."},{"id":"rpt11","text":"You just ran a report you built and want to download the results. What can you use right there?","options":[{"id":"a","text":"CSV — click the CSV button that shows up after you run it","isCorrect":true},{"id":"b","text":"Excel — click the Excel button in the toolbar"},{"id":"c","text":"PDF — click the PDF button next to the chart"},{"id":"d","text":"Nothing — you have to copy and paste from the table"}],"explanation":"After you run a report, a CSV button appears. It downloads every row with your chosen columns as a spreadsheet file. PDF is also available, but CSV is the one right there in the builder."},{"id":"rpt12","text":"You want to change a report you saved earlier. How?","options":[{"id":"a","text":"Open it from the saved list, make your changes, then click Save — it updates the same report","isCorrect":true},{"id":"b","text":"Delete the old one, make changes, and save a new one"},{"id":"c","text":"Saved reports can't be changed — you have to make a new one"},{"id":"d","text":"Right-click its name and choose Edit"}],"explanation":"Open the saved report, change anything you like (columns, filters, chart, and so on), and click Save — it updates the same report. You can also delete a saved report with the red trash icon next to the saved-report menu."}]}"""
